    val parts = content.split("|", limit = 2)
    val apkPath = parts[0].trim()
    val apkFile = File(apkPath)

    if (apkFile.exists() && apkFile.isFile) {
        val info = ctx.packageManager.getPackageArchiveInfo(apkPath, 0)
